const query = $input.first().json.query || {};
const verifyToken = $env.RIFAH_VERIFY_TOKEN || 'rifah_verify_token_2024';

if (query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === verifyToken) {
  return [{ json: { challenge: query['hub.challenge'], valid: true } }];
}
return [{ json: { challenge: 'ERROR', valid: false } }];

// Parse Meta Cloud API Webhook Payload
const body = $input.first().json.body || $input.first().json;

const entry = body?.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;

// Ignore status updates (delivery receipts etc)
if (value?.statuses && !value?.messages) {
  return [{ json: { skip: true, reason: 'status_update' } }];
}

const messages = value?.messages;
if (!messages || messages.length === 0) {
  return [{ json: { skip: true, reason: 'no_message' } }];
}

const msg = messages[0];
const contact = value?.contacts?.[0];

// Extract interactive reply ID (button_reply or list_reply)
let interactiveId = null;
if (msg.type === 'interactive') {
  interactiveId = msg.interactive?.button_reply?.id
    || msg.interactive?.list_reply?.id
    || null;
}

const extracted = {
  skip: false,
  from: msg.from,
  from_name: contact?.profile?.name || 'Unknown',
  message_id: msg.id,
  timestamp: msg.timestamp,
  type: msg.type,
  text: msg.text?.body || '',
  interactive_id: interactiveId,
  phone_number_id: value?.metadata?.phone_number_id,
  // Media fields
  image_id: msg.image?.id || null,
  image_mime: msg.image?.mime_type || null,
  document_id: msg.document?.id || null,
  document_filename: msg.document?.filename || null,
  document_mime: msg.document?.mime_type || null,
};

return [{ json: extracted }];

function supportMenu(tier) {
  const emergency = tier === 'PREMIUM' ? '5️⃣ Emergency Support (24/7)\n' : '';
  return `💬 *TALK TO RIFAH TEAM*\n\nHow can we help you today?\n\n1️⃣ Browse FAQs\n2️⃣ Create Support Ticket\n3️⃣ My Support Tickets\n4️⃣ Contact Information\n${emergency}0️⃣ Back to Main Menu\n\n_Reply with a number_`;
}


// ============================================================
// RIFAH Connect - Flow 1 State Machine
// ============================================================
const msgNode = $('Extract Message').first().json;
const sessionRaw = $('Get Session').first().json;
const memberRaw = $('Get Member').first().json;

const phone = msgNode.from;
const msgType = msgNode.type || 'text';
const rawText = msgNode.text || '';
const interactiveId = msgNode.interactive_id || null;
const rawTextOriginal = interactiveId || rawText.trim();
const msgText = rawTextOriginal.toUpperCase();
const hasMedia = ['image', 'document'].includes(msgType);
const mediaId = hasMedia ? (msgNode.image_id || msgNode.document_id) : null;
const mediaFilename = msgNode.document_filename || ('file_' + Date.now());
const mediaMimeType = msgNode.document_mime || 'image/jpeg';

// Parse session
const sessionDocs = sessionRaw?.data || [];
const sessionDoc = sessionDocs.length > 0 ? sessionDocs[0] : {};
let currentStep = sessionDoc.current_step || 'NEW';
let sessionData = {};
try { sessionData = JSON.parse(sessionDoc.session_data || '{}'); } catch(e) {}
const sessionName = sessionDoc.name || null;

// Parse existing member
const memberDocs = memberRaw?.data || [];
const memberExists = memberDocs.length > 0;
const member = memberExists ? memberDocs[0] : null;

let responseMsg = '';
let nextStep = currentStep;
let action = 'none';
let actionData = {};
let interactivePayload = null;

// ---- HELPER: Main Menu ----
function mainMenu() {
  return `👋 *Welcome to RIFAH Connect!*\n_Connecting 1 Lakh+ Businesses_\n\nPlease select an option:\n\n1️⃣ Register / Update Business\n2️⃣ Find Vendors & Buyers\n3️⃣ Post a Requirement\n4️⃣ My Profile\n5️⃣ Help & Support\n\n_Reply with a number (1-5)_`;
}


// ---- HELPER: Membership Menu ----
function membershipMenu() {
  return `🏷️ *Step 5: Choose Your Membership*\n\n🆓 *FREE TIER (₹0/year)*\n• Manual support\n• 2-3 WhatsApp groups\n• Basic RifahMart listing\n• 24-48 hr response time\n\n⭐ *PREMIUM TIER (₹3,000/year)*\n• 24/7 automated bot\n• 5-10 WhatsApp groups\n• Smart vendor matching\n• Dashboard access\n• Featured RifahMart listing\n• 2-4 hr response time\n\nReply: *FREE* or *PREMIUM*`;
}


function buildMainMenuList() {
  return {
    type: 'list',
    header: { type: 'text', text: '👋 RIFAH Connect' },
    body: { text: 'Connecting 1 Lakh+ Businesses\n\nChoose an option below:' },
    footer: { text: 'RIFAH Chamber of Commerce' },
    action: {
      button: 'View Options',
      sections: [{
        title: 'Main Menu',
        rows: [
          { id: '1', title: '📝 Register / Update', description: 'Register or update your business' },
          { id: '2', title: '🔍 Find Vendors & Buyers', description: 'Browse business opportunities' },
          { id: '3', title: '📋 Post a Requirement', description: 'Share a buy/sell/service lead' },
          { id: '4', title: '👤 My Profile', description: 'View profile & upgrade to Premium' },
          { id: '5', title: '💬 Help & Support', description: 'FAQs, tickets & contact' }
        ]
      }]
    }
  };
}
function buildWelcomeBackButtons(member) {
  const isFree = member.membership_tier === 'FREE' && member.status === 'Active Free';
  const buttons = [
    { type: 'reply', reply: { id: '1', title: '✏️ Update Profile' } },
    { type: 'reply', reply: { id: '2', title: '📋 View Info' } }
  ];
  if (isFree) buttons.push({ type: 'reply', reply: { id: '3', title: '⭐ Upgrade to Premium' } });
  return {
    type: 'button',
    header: { type: 'text', text: `👋 Welcome back, ${member.full_name}!` },
    body: { text: `🪪 RIFAH ID: *${member.rifah_id}*\n⭐ Membership: ${member.membership_tier}\n\nWhat would you like to do?` },
    footer: { text: 'RIFAH Connect' },
    action: { buttons }
  };
}
function buildExistingChoiceButtons(member) {
  const isFree = member.membership_tier === 'FREE' && member.status === 'Active Free';
  const buttons = [
    { type: 'reply', reply: { id: '1', title: '✏️ Update Profile' } },
    { type: 'reply', reply: { id: '2', title: '📋 View Info' } }
  ];
  if (isFree) buttons.push({ type: 'reply', reply: { id: '3', title: '⭐ Upgrade to Premium' } });
  return {
    type: 'button',
    header: { type: 'text', text: '👤 My Profile' },
    body: { text: `🪪 RIFAH ID: *${member.rifah_id}*\n👤 ${member.full_name}\n🏢 ${member.business_name}\n📍 ${member.city_state}\n⭐ ${member.membership_tier} · ${member.status}` },
    footer: { text: 'RIFAH Connect' },
    action: { buttons }
  };
}
function buildTierButtons() {
  return {
    type: 'button',
    header: { type: 'text', text: '🏷️ Choose Membership Tier' },
    body: { text: '🆓 *FREE (₹0/year)*\n• 2-3 WhatsApp groups\n• Basic RifahMart listing\n• 24-48 hr support\n\n⭐ *PREMIUM (₹3,000/year)*\n• 5-10 WhatsApp groups\n• Smart vendor matching\n• Dashboard access\n• 2-4 hr support' },
    footer: { text: 'RIFAH Chamber of Commerce' },
    action: {
      buttons: [
        { type: 'reply', reply: { id: 'FREE', title: '🆓 Free Tier' } },
        { type: 'reply', reply: { id: 'PREMIUM', title: '⭐ Premium — ₹3,000' } }
      ]
    }
  };
}
function buildPhoneConfirmButtons(phone) {
  return {
    type: 'button',
    header: { type: 'text', text: '📱 Confirm Your Number' },
    body: { text: `Is this your WhatsApp number?\n\n*+${phone}*` },
    footer: { text: 'Reply YES to confirm or type a different number' },
    action: {
      buttons: [
        { type: 'reply', reply: { id: 'YES', title: '✅ Yes, confirm' } },
        { type: 'reply', reply: { id: 'CHANGE', title: '✏️ Use different number' } }
      ]
    }
  };
}

// ─── LEAD ID / ADMIN PATTERN DETECTION ──────────────────────────────────────
// ─── LEAD ID PATTERN DETECTION ───────────────────────────────
const leadPattern = /^LEAD-(FREE|PREM)-\d{4}-\d+$/i;
const isLeadId = leadPattern.test(rawTextOriginal.trim());

// Admin command detection (from admin WhatsApp number)
const adminPhone = sessionData._admin_phone || '';
const connectMatch = rawTextOriginal.match(/^CONNECT\s+(\S+)\s+(\S+)/i);
const declineMatch = rawTextOriginal.match(/^DECLINE\s+(\S+)\s+(\S+)/i);
if (connectMatch || declineMatch) {
  const m = connectMatch || declineMatch;
  action = 'admin_approval';
  actionData = {
    command: connectMatch ? 'CONNECT' : 'DECLINE',
    lead_id: m[1],
    vendor_id: m[2],
    admin_phone: phone
  };

// ── Append to chat history ──────────────────────────────────────────────────
const _ch = sessionData._chat || [];
_ch.push({ id: `msg_${Date.now()}_in`, ts: new Date().toISOString(), dir: 'inbound', type: msgType, content: rawTextOriginal || '[media]', wa_msg_id: msgNode.id || '' });
if (responseMsg) { _ch.push({ id: `msg_${Date.now()}_out`, ts: new Date().toISOString(), dir: 'outbound', type: 'text', content: responseMsg, step: nextStep }); }
sessionData._chat = _ch;

return [{ json: { phone, responseMsg: '', nextStep: currentStep, action, actionData: JSON.stringify(actionData), sessionData: JSON.stringify(sessionData), sessionName, currentStep, shouldSendMsg: false, skip: false } }];
}



// ─── GLOBAL NAVIGATION: HOME / RESTART ───────────────────────────────────────
// Users can type HOME (→ main menu) or RESTART (→ restart current flow section)
// at any point except locked/transient states.
const NAV_LOCKED = ['NEW', 'MENU', 'PROCESSING', 'COMPLETED', 'PAYMENT_PENDING', 'ACTIVE_CONVERSATION'];
if (!NAV_LOCKED.includes(currentStep) && (msgText === 'HOME' || msgText === 'RESTART')) {

  if (msgText === 'HOME') {
    nextStep = 'MENU';
    interactivePayload = buildMainMenuList();

  } else {
    // ── RESTART: map current step to its flow's entry point ──
    const REG_STEPS   = ['EXISTING_CHOICE','Q1','Q2','Q3','Q4','Q5','Q6','DOC_UPLOAD','PRODUCT_UPLOAD','TIER_SELECT','PAYMENT_WAIT'];
    const LEAD_STEPS  = ['LEAD_TYPE','LEAD_DESC','LEAD_LOC','LEAD_URGENCY','LEAD_CREATE'];
    const FIND_STEPS  = ['SEARCH_METHOD','LOCATION_INPUT','CATEGORY_SELECT','WAITING_LEADS','WAITING_LEAD_DETAIL','VENDOR_INTRO','VENDOR_CONFIRM','VENDOR_SCORE','VENDOR_SELECTION','VENDOR_SUBMIT','SAVE_SEARCH_NAME'];
    const SUPP_STEPS  = ['SUPPORT_CATEGORY','FAQ_CATEGORY','FAQ_SELECT','FAQ_FEEDBACK','TICKET_TYPE','TICKET_DESC','TICKET_ATTACH','TICKET_VIEW'];

    if (REG_STEPS.includes(currentStep)) {
      ['full_name','business_name','city_state','industry','years_operating',
       'doc_media_id','product_materials','tier','is_update','confirmed_phone'].forEach(k => delete sessionData[k]);
      nextStep = 'Q1';
      responseMsg = `🔄 *Starting over...*\n\n✅ Let's get you registered with RIFAH!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?`;

    } else if (LEAD_STEPS.includes(currentStep)) {
      ['lead_type','lead_desc','lead_loc','lead_urgency','flow'].forEach(k => delete sessionData[k]);
      const isP2 = member?.membership_tier === 'PREMIUM' && member?.status === 'Active Premium';
      sessionData.flow = isP2 ? 'flow2b' : 'flow2a';
      nextStep = 'LEAD_TYPE';
      responseMsg = isP2
        ? `🔄 *Starting over...*\n\n⭐ *PREMIUM Share Lead*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* — I need to purchase\n2️⃣ *SELL* — I have products to sell\n3️⃣ *SERVICE NEED* — I need a service\n4️⃣ *SERVICE OFFER* — I provide a service\n\n_Reply: 1, 2, 3, or 4_`
        : `🔄 *Starting over...*\n\n📋 *Share a Lead (Free)*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* — I need to purchase\n2️⃣ *SELL* — I have products to sell\n3️⃣ *SERVICE NEED* — I need a service\n4️⃣ *SERVICE OFFER* — I provide a service\n\n_Reply: 1, 2, 3, or 4_`;

    } else if (FIND_STEPS.includes(currentStep)) {
      ['search_method','search_category','search_location','vendor_list','current_lead_id','lead_id'].forEach(k => delete sessionData[k]);
      const isPremF = member?.membership_tier === 'PREMIUM' && member?.status === 'Active Premium';
      const tierNote = isPremF
        ? `\n\n⭐ *Premium Access:* Search all leads across India`
        : `\n\n⚠️ *Free Tier:* Search limited to your industry + city\n💡 Upgrade to Premium for full access`;
      nextStep = 'SEARCH_METHOD';
      responseMsg = `🔄 *Starting over...*\n\n🔍 *FIND LEAD*\n\nSearch for business opportunities posted by buyers.\n\n*How to search:*\n1️⃣ Browse by Category\n2️⃣ Search by Location\n3️⃣ Browse by Urgency\n4️⃣ View All Recent Leads\n5️⃣ My Saved Searches _(Premium only)_\n6️⃣ My Responses\n0️⃣ Back to Main Menu${tierNote}\n\n_Reply with a number (0-6)_`;

    } else if (SUPP_STEPS.includes(currentStep)) {
      ['ticket_type','ticket_desc','ticket_attach','faq_category','faq_id','active_ticket_id'].forEach(k => delete sessionData[k]);
      nextStep = 'SUPPORT_CATEGORY';
      responseMsg = `🔄 *Starting over...*\n\n` + supportMenu(member?.membership_tier);

    } else {
      nextStep = 'MENU';
      interactivePayload = buildMainMenuList();
    }
  }


// ── Append to chat history ──────────────────────────────────────────────────
const _ch = sessionData._chat || [];
_ch.push({ id: `msg_${Date.now()}_in`, ts: new Date().toISOString(), dir: 'inbound', type: msgType, content: rawTextOriginal || '[media]', wa_msg_id: msgNode.id || '' });
if (responseMsg) { _ch.push({ id: `msg_${Date.now()}_out`, ts: new Date().toISOString(), dir: 'outbound', type: 'text', content: responseMsg, step: nextStep }); }
sessionData._chat = _ch;

return [{ json: { phone, responseMsg, nextStep, action: 'none', actionData: JSON.stringify({}), sessionData: JSON.stringify(sessionData), sessionName, currentStep, msgType, hasMedia, mediaId, shouldSendMsg: !!(responseMsg || interactivePayload), interactivePayload: interactivePayload ? JSON.stringify(interactivePayload) : null, skip: false } }];
}


// ─── GLOBAL NAVIGATION: BACK ─────────────────────────────────────────────────
// During the registration flow, typing BACK returns the user one step and
// clears the data they entered for that step so they can re-enter it.
const REG_BACK_MAP = {
  'Q2':             { prev: 'Q1',             clear: ['full_name'],
    msg: `◀️ *Going back...*\n\n*Question 1 of 6*\n\n👤 What is your *full name*?\n\n_Type *HOME* for main menu or *RESTART* to start over_` },
  'Q3':             { prev: 'Q2',             clear: ['business_name'],
    msg: `◀️ *Going back...*\n\n*Question 2 of 6*\n\n🏢 What is your *business name*?\n\n_Type *BACK* for previous step, *HOME* for main menu, or *RESTART* to start over_` },
  'Q4':             { prev: 'Q3',             clear: ['city_state'],
    msg: `◀️ *Going back...*\n\n*Question 3 of 6*\n\n📍 Which *city and state* is your business located in?\n_Example: Pune, Maharashtra_\n\n_Type *BACK* for previous step, *HOME* for main menu, or *RESTART* to start over_` },
  'Q5':             { prev: 'Q4',             clear: ['industry'],
    msg: `◀️ *Going back...*\n\n*Question 4 of 6*\n\n🏭 What is your *industry / business type*?\n_Examples: Manufacturing, Trading, Services, Retail_\n\n_Type *BACK* for previous step, *HOME* for main menu, or *RESTART* to start over_` },
  'Q6':             { prev: 'Q5',             clear: ['years_operating'],
    msg: `◀️ *Going back...*\n\n*Question 5 of 6*\n\n📅 How many *years* has your business been operating?\n_Reply with a number (e.g., 5)_\n\n_Type *BACK* for previous step, *HOME* for main menu, or *RESTART* to start over_` },
  'DOC_UPLOAD':     { prev: 'Q6',             clear: ['confirmed_phone'],
    msg: null,
    interactiveMsg: buildPhoneConfirmButtons(phone) },
  'PRODUCT_UPLOAD': { prev: 'DOC_UPLOAD',    clear: ['doc_media_id','doc_filename','doc_media_type','doc_mime'],
    msg: `◀️ *Going back...*\n\n📄 *Step 3: Document Verification*\n\nPlease upload your *business verification document*:\n\n• Udyam Registration Certificate\n• OR GST Registration Certificate\n\n_Accepted: PDF, JPG, PNG_\n\n_Type *BACK* for previous step, *HOME* for main menu, or *RESTART* to start over_` },
  'TIER_SELECT':    { prev: 'PRODUCT_UPLOAD', clear: ['product_materials'],
    msg: `◀️ *Going back...*\n\n📦 *Step 4: Product Materials* _(Optional)_\n\nUpload your product materials to attract more buyers:\n\n• Product catalogs (PDF)\n• Product images (JPG/PNG)\n• Brochures / marketing materials\n\n_Reply *SKIP* to skip or *DONE* when finished uploading._\n\n_Type *BACK* for previous step, *HOME* for main menu, or *RESTART* to start over_` },
  'PAYMENT_WAIT':   { prev: 'TIER_SELECT',   clear: ['tier'],
    msg: null,
    interactiveMsg: buildTierButtons() },
};

if (msgText === 'BACK' && !NAV_LOCKED.includes(currentStep)) {
  if (currentStep === 'Q1') {
    responseMsg = `⬅️ You are already at the *first step*.\n\nType *RESTART* to re-enter your name, or *HOME* for the main menu.`;

// ── Append to chat history ──────────────────────────────────────────────────
const _ch = sessionData._chat || [];
_ch.push({ id: `msg_${Date.now()}_in`, ts: new Date().toISOString(), dir: 'inbound', type: msgType, content: rawTextOriginal || '[media]', wa_msg_id: msgNode.id || '' });
if (responseMsg) { _ch.push({ id: `msg_${Date.now()}_out`, ts: new Date().toISOString(), dir: 'outbound', type: 'text', content: responseMsg, step: nextStep }); }
sessionData._chat = _ch;

return [{ json: { phone, responseMsg, nextStep: 'Q1', action: 'none', actionData: JSON.stringify({}), sessionData: JSON.stringify(sessionData), sessionName, currentStep, msgType, hasMedia, mediaId, shouldSendMsg: true, interactivePayload: null, skip: false } }];
  }
  const backEntry = REG_BACK_MAP[currentStep];
  if (backEntry) {
    backEntry.clear.forEach(k => delete sessionData[k]);
    if (backEntry.interactiveMsg) interactivePayload = backEntry.interactiveMsg;

// ── Append to chat history ──────────────────────────────────────────────────
const _ch = sessionData._chat || [];
_ch.push({ id: `msg_${Date.now()}_in`, ts: new Date().toISOString(), dir: 'inbound', type: msgType, content: rawTextOriginal || '[media]', wa_msg_id: msgNode.id || '' });
if (responseMsg) { _ch.push({ id: `msg_${Date.now()}_out`, ts: new Date().toISOString(), dir: 'outbound', type: 'text', content: responseMsg, step: nextStep }); }
sessionData._chat = _ch;

return [{ json: { phone, responseMsg: backEntry.msg || '', nextStep: backEntry.prev, action: 'none', actionData: JSON.stringify({}), sessionData: JSON.stringify(sessionData), sessionName, currentStep, msgType, hasMedia, mediaId, shouldSendMsg: !!(responseMsg || interactivePayload), interactivePayload: interactivePayload ? JSON.stringify(interactivePayload) : null, skip: false } }];
  }
  // BACK not handled for non-registration steps — fall through
}

switch(currentStep) {

  case 'NEW':
    sessionData = { phone };
    if (isLeadId && memberExists) {
      // Vendor sends a lead ID with no existing session
      const isPremVendor = member?.membership_tier === 'PREMIUM' && member?.status === 'Active Premium';
      nextStep = 'VENDOR_INTRO';
      action = isPremVendor ? 'vendor_lookup_prem' : 'vendor_lookup_free';
      actionData = { lead_id: rawTextOriginal.trim().toUpperCase(), phone, memberId: member?.name || '', memberTier: member?.membership_tier || 'FREE', sessionName };
      sessionData.current_lead_id = rawTextOriginal.trim().toUpperCase();
      sessionData.lead_id = rawTextOriginal.trim().toUpperCase();
      sessionData.is_premium = isPremVendor;
      responseMsg = `🔍 *Looking up lead details...*`;
    } else if (memberExists) {
      if (msgText === '1') {
        // User chose "Register / Update" from menu
        responseMsg = `✏️ Let's update your profile!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?\n_(Current: ${member.full_name})_`;
        nextStep = 'Q1';
        sessionData.is_update = true;
        sessionData.existing_member_id = member.name;
        sessionData.existing_rifah_id = member.rifah_id;
      } else {
        interactivePayload = buildWelcomeBackButtons(member);
        nextStep = 'EXISTING_CHOICE';
        sessionData.existing_member_id = member.name;
        sessionData.existing_rifah_id = member.rifah_id;
      }
    } else {
      if (msgText === '1') {
        // User chose "Register" from the main menu list
        responseMsg = `✅ Let's get you registered with RIFAH!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?`;
        nextStep = 'Q1';
      } else if (msgText === '2') {
        responseMsg = `⚠️ You need to be a registered RIFAH member to share leads.\n\nReply *1* to register your business first.`;
        nextStep = 'MENU';
        interactivePayload = buildMainMenuList();
      } else if (msgText === '3') {
        responseMsg = `⚠️ You need to be a registered RIFAH member to find leads.\n\nReply *1* to register first.`;
        nextStep = 'MENU';
        interactivePayload = buildMainMenuList();
      } else if (msgText === '4' || msgText === '5') {
        responseMsg = `⚠️ You need to be a registered RIFAH member first.\n\nReply *1* to register.`;
        nextStep = 'MENU';
        interactivePayload = buildMainMenuList();
      } else {
        interactivePayload = buildMainMenuList();
        nextStep = 'MENU';
      }
    }
    break;

  case 'MENU':
    if (msgText === '1') {
      if (memberExists) {
        interactivePayload = buildWelcomeBackButtons(member);
        nextStep = 'EXISTING_CHOICE';
        sessionData.existing_member_id = member.name;
        sessionData.existing_rifah_id = member.rifah_id;
      } else {
        responseMsg = `✅ Let's get you registered with RIFAH!\n\n*Question 1 of 6*\n\n👤 What is your *full name*?`;
        nextStep = 'Q1';
      }
    } else if (msgText === '2') {
      if (!memberExists) {
        responseMsg = `⚠️ You need to be a registered RIFAH member to share leads.\n\nReply *1* to register your business first.`;
      } else {
        nextStep = 'LEAD_TYPE';
        if (member.membership_tier === 'PREMIUM' && member.status === 'Active Premium') {
          responseMsg = `⭐ *PREMIUM Share Lead*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* — I need to purchase\n2️⃣ *SELL* — I have products to sell\n3️⃣ *SERVICE NEED* — I need a service\n4️⃣ *SERVICE OFFER* — I provide a service\n\n_Reply: 1, 2, 3, or 4_`;
          sessionData.flow = 'flow2b';
        } else {
          responseMsg = `📋 *Share a Lead (Free)*\n\nWhat type of requirement do you have?\n\n1️⃣ *BUY* — I need to purchase\n2️⃣ *SELL* — I have products to sell\n3️⃣ *SERVICE NEED* — I need a service\n4️⃣ *SERVICE OFFER* — I provide a service\n\n_Reply: 1, 2, 3, or 4_`;
          sessionData.flow = 'flow2a';
        }
      }
    } else if (msgText === '3') {
      if (!memberExists) {
        responseMsg = `⚠️ You need to be a registered RIFAH member to find leads.\n\nReply *1* to register first.`;
      } else {
        nextStep = 'SEARCH_METHOD';
