        responseMsg = `❌ Invalid selection. Reply with a number from the list, or *0* to go back.\n\n_Type *HOME* for Main Menu or *RESTART* to begin this section again_`;
      }
    }
    break;
  }

  case 'FAQ_FEEDBACK': {
    const curFaq = sessionData.f5_current_faq || {};
    if (msgText === '0' || msgText === 'BACK') {
      nextStep = 'FAQ_SELECT';
      action = 'f5_faq_fetch';
      actionData = { fetchType: 'faq_list', category: sessionData.f5_last_category || null, memberTier: member?.membership_tier || 'FREE', phone };
      responseMsg = '⏳ Loading FAQs...';
    } else if (msgText.toUpperCase() === 'TICKET') {
      nextStep = 'TICKET_TYPE';
      responseMsg = `🎫 *CREATE SUPPORT TICKET*\n\nWhat type of support do you need?\n\n1️⃣ Technical Issue\n2️⃣ Billing & Payments\n3️⃣ Membership Questions\n4️⃣ General Inquiry\n5️⃣ Complaint\n6️⃣ Feature Request\n0️⃣ Back\n\n_Reply with a number_`;
    } else if (msgText.toUpperCase() === 'YES') {
      nextStep = 'SUPPORT_CATEGORY';
      action = 'f5_faq_stats';
      actionData = { faqId: curFaq.faq_id, statType: 'helpful', phone };
      responseMsg = `✅ Thank you for your feedback!\n\nNeed more help?\n*BACK* — More FAQs\n*TICKET* — Create support ticket\n*MENU* — Main menu\n\nReply *0* to go back to support menu`;
    } else if (msgText.toUpperCase() === 'NO') {
      nextStep = 'SUPPORT_CATEGORY';
      responseMsg = `Sorry this wasn't helpful.\n\nWould you like to:\n1️⃣ Create support ticket\n2️⃣ Browse other FAQs\n0️⃣ Back to menu\n\n_Reply with a number_`;
    } else if (msgText.toUpperCase() === 'MENU') {
      nextStep = 'MENU';
      responseMsg = mainMenu();
    } else {
      responseMsg = `*Was this FAQ helpful?*\n\nReply *YES* or *NO*\nOr *BACK* for more FAQs\nOr *TICKET* to get personal support`;
    }
    break;
  }

  case 'TICKET_TYPE': {
    const TICKET_TYPES = ['TECHNICAL', 'BILLING', 'GENERAL', 'GENERAL', 'COMPLAINT', 'FEATURE_REQUEST', 'MEMBERSHIP'];
    if (msgText === '0' || msgText === 'BACK') {
      nextStep = 'SUPPORT_CATEGORY';
      responseMsg = supportMenu(member?.membership_tier);
    } else if (msgText === '1' && sessionData.f5_emergency) {
      // Emergency URGENT ticket
      nextStep = 'TICKET_DESC';
      sessionData.f5_ticket_type = 'TECHNICAL';
      sessionData.f5_priority_override = 'URGENT';
      responseMsg = `🚨 *URGENT TECHNICAL SUPPORT*\n\nPlease describe your critical issue:\n\n• What is happening?\n• What is the business impact?\n• When did it start?\n\n_Type your message below_`;
    } else {
      const tidx = parseInt(msgText) - 1;
      const typeMap = { 0: 'TECHNICAL', 1: 'BILLING', 2: 'MEMBERSHIP', 3: 'GENERAL', 4: 'COMPLAINT', 5: 'FEATURE_REQUEST' };
      if (tidx >= 0 && tidx <= 5) {
        nextStep = 'TICKET_DESC';
        sessionData.f5_ticket_type = typeMap[tidx];
        delete sessionData.f5_emergency;
        responseMsg = `✍️ *DESCRIBE YOUR ISSUE*\n\nPlease describe your issue in detail:\n\n• What were you trying to do?\n• What happened instead?\n• Any error messages?\n\n_Type your message below_`;
      } else {
        responseMsg = `🎫 *CREATE SUPPORT TICKET*\n\nWhat type of support do you need?\n\n1️⃣ Technical Issue\n2️⃣ Billing & Payments\n3️⃣ Membership Questions\n4️⃣ General Inquiry\n5️⃣ Complaint\n6️⃣ Feature Request\n0️⃣ Back\n\n_Reply with a number_`;
      }
    }
    break;
  }

  case 'TICKET_DESC': {
    if (msgText === '0' || msgText === 'BACK') {
      nextStep = 'TICKET_TYPE';
      responseMsg = `🎫 *CREATE SUPPORT TICKET*\n\nWhat type of support do you need?\n\n1️⃣ Technical Issue\n2️⃣ Billing & Payments\n3️⃣ Membership Questions\n4️⃣ General Inquiry\n5️⃣ Complaint\n6️⃣ Feature Request\n0️⃣ Back\n\n_Reply with a number_`;
    } else if (msgText.length < 10) {
      responseMsg = `⚠️ Please provide more detail about your issue (at least 10 characters).\n\n_Type your message below_\n\n_Type *HOME* for Main Menu or *RESTART* to begin this section again_`;
    } else {
      nextStep = 'TICKET_ATTACH';
      sessionData.f5_ticket_desc = msgText;
      responseMsg = `📎 *ATTACH FILE?*\n\nWould you like to attach a screenshot or file?\nThis helps our team resolve your issue faster.\n\n1️⃣ Yes — attach file\n2️⃣ No — submit now\n\n_Reply with a number_`;
    }
    break;
  }

  case 'TICKET_ATTACH': {
    if (msgText === '1' || msgText.toUpperCase() === 'YES') {
      nextStep = 'TICKET_ATTACH';
      responseMsg = `📎 Please send your screenshot or file now.\n\n_Send the image/document in your next message_\n\n_Type *HOME* for Main Menu or *RESTART* to begin this section again_`;
    } else {
      // No attachment — create ticket
      nextStep = 'SUPPORT_CATEGORY';
      action = 'f5_ticket_create';
      actionData = {
        ticketType: sessionData.f5_ticket_type || 'GENERAL',
        description: sessionData.f5_ticket_desc || 'No description provided',
        priorityOverride: sessionData.f5_priority_override || null,
        memberId: member?.rifah_id || '',
        memberName: member?.full_name || member?.business_name || '',
        memberPhone: phone,
        memberTier: member?.membership_tier || 'FREE',
        phone,
      };
      responseMsg = '⏳ Creating your support ticket...';
    }
    break;
  }

  case 'TICKET_VIEW': {
    const f5tickets = sessionData.f5_tickets || [];
    if (msgText === '0' || msgText === 'BACK') {
      nextStep = 'SUPPORT_CATEGORY';
      responseMsg = supportMenu(member?.membership_tier);
    } else if (msgText.toUpperCase().startsWith('TICKET-')) {
      // User typed a ticket ID
      const ticketId = msgText.toUpperCase();
      const ticket = f5tickets.find(t => t.ticket_id === ticketId);
      if (ticket) {
        nextStep = 'ACTIVE_CONVERSATION';
        sessionData.f5_active_ticket_id = ticketId;
        sessionData.f5_active_ticket = ticket;
        const log = JSON.parse(ticket.conversation_log || '[]');
        const histLines = log.slice(-3).map(m => `[${new Date(m.timestamp).toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit'})}] ${m.from === 'user' ? '👤 You' : '👨‍💼 Support'}: ${m.message.substring(0, 80)}`).join('\n');
        responseMsg = `🎫 *TICKET ${ticket.ticket_id}*\n\n📋 Type: ${ticket.ticket_type}\n⚡ Priority: ${ticket.priority}\n📊 Status: ${ticket.status}\n\nIssue:\n${(ticket.description || '').substring(0, 200)}\n\n━━━━━━━━━━━━━━━━━━━━━━\n${histLines ? 'Recent messages:\n' + histLines + '\n\n' : ''}Reply to send a message to support\nOr *0* to go back`;
      } else {
        responseMsg = `❌ Ticket not found. Reply with your ticket ID (e.g., TICKET-2026-000001)\nOr *0* to go back.\n\n_Type *HOME* for Main Menu or *RESTART* to begin this section again_`;
      }
    } else {
      responseMsg = `🎫 *MY SUPPORT TICKETS*\n\nReply with your ticket ID to view details\n(e.g., TICKET-2026-000001)\n\nOr *0* to go back to support menu`;
    }
    break;
  }

  case 'ACTIVE_CONVERSATION': {
    const activeId = sessionData.f5_active_ticket_id;
    if (msgText === '0' || msgText === 'BACK' || msgText.toUpperCase() === 'MENU') {
      nextStep = 'SUPPORT_CATEGORY';
      delete sessionData.f5_active_ticket_id;
      delete sessionData.f5_active_ticket;
      responseMsg = supportMenu(member?.membership_tier);
    } else if (msgText.toUpperCase() === 'TICKETS') {
      nextStep = 'TICKET_VIEW';
      action = 'f5_ticket_list';
      actionData = { memberId: member?.rifah_id || '', memberTier: member?.membership_tier || 'FREE', phone };
      responseMsg = '⏳ Loading your tickets...';
    } else if (activeId) {
      // Forward message to support (store in ticket conversation log)
      nextStep = 'ACTIVE_CONVERSATION';
      action = 'f5_ticket_reply';
      actionData = { ticketId: activeId, message: msgText, memberName: member?.full_name || member?.business_name || '', phone };
      responseMsg = "✅ Message sent to support team. We'll respond as soon as possible.";
    } else {
      nextStep = 'SUPPORT_CATEGORY';
      responseMsg = supportMenu(member?.membership_tier);
    }
    break;
  }

  default: {
    sessionData = { phone };
    responseMsg = mainMenu();
    nextStep = 'MENU';
    break;
  }
}

return [{
  json: {
    phone,
    responseMsg,
    nextStep,
    action,
    actionData: JSON.stringify(actionData),
    sessionData: JSON.stringify(sessionData),
    sessionName,
    currentStep,
    msgType,
    hasMedia,
    mediaId,
    shouldSendMsg: !!(responseMsg || interactivePayload),
    interactivePayload: interactivePayload ? JSON.stringify(interactivePayload) : null,
    skip: false
  }
}];

