const response = $input.first().json;
const smData = $('State Machine').first().json;

const defaultQuestions = [
  { q: 'Can you supply/provide this requirement?', type: 'yes_no' },
  { q: 'Do you have the required certifications or qualifications?', type: 'yes_no' },
  { q: 'What is your delivery/completion timeline?', type: 'text' },
  { q: 'What is your price or rate for this requirement?', type: 'text' },
  { q: 'Can you handle any additional services related to this?', type: 'yes_no' },
  { q: 'Do you have past experience with similar clients or projects?', type: 'yes_no' }
];

let questions = [];
try {
  const content = response.choices[0].message.content;
  let parsed;
  try { parsed = JSON.parse(content); }
  catch(e) {
    const cleaned = content.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
    parsed = JSON.parse(cleaned);
  }
  questions = parsed.questions || [];
  if (!questions.length) throw new Error('empty');
} catch(e) {
  questions = defaultQuestions;
}

// Ensure max 6 and each has q and type
questions = questions.slice(0, 6).map(q => ({
  q: typeof q === 'object' ? (q.q || q.question || String(q)) : String(q),
  type: (typeof q === 'object' && q.type) ? q.type : 'text'
}));

const q1 = questions[0];
const q1Text = q1 ? q1.q : 'Can you fulfill this requirement?';
const q1Type = q1 ? q1.type : 'yes_no';

return [{ json: {
  questions,
  q1Text,
  q1Type,
  totalQuestions: questions.length,
  phone: smData.phone,
  sessionName: smData.sessionName,
  sessionData: smData.sessionData,
