  firstQuestion: `🤖 *Vendor Qualification*\n\nI'll ask ${questions.length} questions to validate your capability for this lead.\n\n*Question 1 of ${questions.length}:*\n${q1Text}\n\n${q1Type === 'yes_no' ? '_Reply: YES or NO_' : '_Please specify:_'}`
}}];

