const response = $input.first().json;
const smData = $('State Machine').first().json;
const actionData = JSON.parse(smData.actionData || '{}');
const sessionData = JSON.parse(smData.sessionData || '{}');

const defaultQuestions = [
  { q: 'Can you supply or provide this requirement?', type: 'yes_no' },
  { q: 'Do you have the required certifications or qualifications?', type: 'yes_no' },
  { q: 'What is your delivery or completion timeline?', type: 'text' },
  { q: 'What is your price or rate for this requirement?', type: 'text' },
  { q: 'Can you handle the full quantity or scope required?', type: 'yes_no' },
  { q: 'Do you have past experience with similar projects?', type: 'yes_no' }
];

let questions = [];
try {
  const content = response?.choices?.[0]?.message?.content || '';
  let parsed;
  try { parsed = JSON.parse(content); }
  catch(e) {
    const cleaned = content.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
    parsed = JSON.parse(cleaned);
  }
  questions = parsed.questions || [];
  if (!questions.length) throw new Error('empty');
} catch(e) {
  questions = defaultQuestions;
}

questions = questions.slice(0, 6).map(q => ({
  q: typeof q === 'object' ? (q.q || q.question || String(q)) : String(q),
  type: typeof q === 'object' ? (q.type || 'text') : 'text'
}));

const leadDetails = JSON.parse(actionData.leadDetails || '{}');
const q1Text = `🤖 *Vendor Qualification*\n\nI'll ask you 6 quick questions to check your fit for this lead.\n\n📋 *Lead:* ${leadDetails.title || actionData.leadId}\n\n━━━━━━━━━━━━━━━━━━━━━━\n*Question 1 of 6*\n\n${questions[0].q}${questions[0].type === 'yes_no' ? '\n\n_Reply YES or NO_' : '\n\n_Type your answer_'}`;

const phone = smData.phone;
const newSession = {
  ...sessionData,
  vendor_questions: questions,
  vendor_question_1: q1Text,
  lead_type: leadDetails.lead_type || '',
  lead_description: leadDetails.description || '',
  lead_location: leadDetails.location || '',
  lead_budget: leadDetails.budget || '',
  lead_urgency: leadDetails.urgency || '',
  lead_title: leadDetails.title || '',
  vendor_id: actionData.vendorId || '',
  vendor_name: actionData.vendorName || '',
  member_doc_name: actionData.memberId || '',
  is_premium: actionData.isPremium || false,
  qualification_source: 'flow3'
};

return [{ json: { phone, questions, q1Text, sessionData: JSON.stringify(newSession), sessionName: smData.sessionName } }];

