parameters.jsCode:
const smData = $('State Machine').first().json;
const phone = smData.phone;
const actionData = JSON.parse(smData.actionData || '{}');
const rifah_id = actionData.rifah_id || actionData.memberId || '';
const leadsRaw = $input.first().json;
const allLeads = leadsRaw?.data || [];

// Find leads where this vendor responded
const myResponses = allLeads.filter(lead => {
  try {
    const vendors = JSON.parse(lead.interested_vendors || '[]');
    return vendors.some(v => v.vendor_id === rifah_id);
  } catch(e) { return false; }
});

function getMyVendorEntry(lead) {
  try {
    const vendors = JSON.parse(lead.interested_vendors || '[]');
    return vendors.find(v => v.vendor_id === rifah_id) || null;
  } catch(e) { return null; }
}

function timeAgo(c) {
  if (!c) return '';
  const h = Math.floor((Date.now() - new Date(c).getTime()) / 3600000);
  return h < 1 ? 'Just now' : h < 24 ? h + 'h ago' : Math.floor(h/24) + 'd ago';
}

const pending = myResponses.filter(l => { const v = getMyVendorEntry(l); return v?.status === 'Pending Admin Approval'; });
const approved = myResponses.filter(l => { const v = getMyVendorEntry(l); return v?.status === 'Approved - Connected'; });
const declined = myResponses.filter(l => { const v = getMyVendorEntry(l); return v?.status === 'Declined by Admin'; });

let msg = `📊 *MY LEAD RESPONSES*\n\nTotal: ${myResponses.length} responses\n`;

if (myResponses.length === 0) {
  msg += `\nYou haven't responded to any leads yet.\n\nStart searching: Reply *SEARCH*`;
} else {
  if (pending.length > 0) {
    msg += `\n━━━━━━━━━━━━━━━━━━━━━━\n*PENDING REVIEW (${pending.length})*\n\n`;
    msg += pending.slice(0, 5).map((l, i) => {
      const v = getMyVendorEntry(l);
      return `${i+1}. *${l.lead_id}*\n   ${(l.title||'').substring(0,45)}...\n   📊 Score: ${v?.compatibility_score||0}/100\n   🕐 ${timeAgo(v?.submitted_at)}`;
    }).join('\n\n');
  }

  if (approved.length > 0) {
    msg += `\n\n━━━━━━━━━━━━━━━━━━━━━━\n*✅ APPROVED - CONNECTED (${approved.length})*\n\n`;
    msg += approved.slice(0, 3).map((l, i) => {
      return `${i+1}. *${l.lead_id}*\n   ${(l.title||'').substring(0,45)}...`;
    }).join('\n\n');
  }

  if (declined.length > 0) {
    msg += `\n\n━━━━━━━━━━━━━━━━━━━━━━\n*❌ DECLINED (${declined.length})*\n\n`;
    msg += declined.slice(0, 3).map(l => `• ${l.lead_id} — ${(l.title||'').substring(0,40)}`).join('\n');
  }

  msg += `\n\n━━━━━━━━━━━━━━━━━━━━━━\nReply *0* to go back`;
}

return [{ json: { phone, msg } }];

const smData = $('State Machine').first().json;
const phone = smData.phone;
const actionData = JSON.parse(smData.actionData || '{}');

let savedSearches = [];
try { savedSearches = JSON.parse(actionData.searchPreferences || '[]'); } catch(e) {}

const alertEnabled = actionData.alertEnabled || 0;

let msg = '';
if (savedSearches.length === 0) {
  msg = `⭐ *MY SAVED SEARCHES*

${alertEnabled ? '🔔 Daily alerts: ON' : '🔕 Daily alerts: OFF'}

You haven't saved any searches yet.

*How to save a search:*
1. Browse leads by category, location, or urgency
2. Reply *SAVE SEARCH* when viewing the results list
3. Name your search for quick access

Saved searches will appear here with daily new-lead counts.

Reply *0* to go back`;
} else {
  function timeAgo(c) {
    if (!c) return 'Never';
    const h = Math.floor((Date.now() - new Date(c).getTime()) / 3600000);
    return h < 1 ? 'Just now' : h < 24 ? h + 'h ago' : Math.floor(h/24) + 'd ago';
  }

  const searchLines = savedSearches.slice(0, 10).map((s, i) => {
    const filters = s.filters || {};
    const parts = [
      filters.category ? `Category: ${filters.category}` : null,
      filters.location ? `Location: ${filters.location}` : null,
      filters.urgency ? `Urgency: ${filters.urgency}` : null,
    ].filter(Boolean).join(', ') || 'All leads';

    return `*${i+1}.* ${s.name}\n   🔍 ${parts}\n   🕐 Saved: ${timeAgo(s.created_at)}`;
  }).join('\n\n');

  msg = `⭐ *MY SAVED SEARCHES*

${alertEnabled ? '🔔 Daily alerts: ON' : '🔕 Daily alerts: OFF'}

━━━━━━━━━━━━━━━━━━━━━━
${searchLines}
━━━━━━━━━━━━━━━━━━━━━━

Reply with search number to run it
Or *ALERTS* to toggle daily notifications
Or *0* to go back`;
}

return [{ json: { phone, msg } }];

const smData = $('State Machine').first().json;
const phone = smData.phone;
const actionData = JSON.parse(smData.actionData || '{}');
const sessionData = JSON.parse(smData.sessionData || '{}');

// Get existing saved searches from member (passed via actionData from a prior get-member call)
// We'll fetch fresh from ERPNext in the next node
return [{ json: {
  phone,
  memberId: actionData.memberId || '',
  searchName: actionData.searchName || '',
  searchCriteria: actionData.searchCriteria || '{}',
} }];

const buildData = $('Build Save Search Data').first().json;
const memberRaw = $input.first().json;
const members = memberRaw?.data || [];
const member = members.length > 0 ? members[0] : {};

let savedSearches = [];
try { savedSearches = JSON.parse(member.search_preferences || '[]'); } catch(e) {}

const newSearch = {
  name: buildData.searchName,
  filters: (() => { try { return JSON.parse(buildData.searchCriteria); } catch(e) { return {}; } })(),
  created_at: new Date().toISOString(),
  last_run: null,
  alert_enabled: false
};

savedSearches.push(newSearch);

return [{ json: {
  phone: buildData.phone,
  memberDocName: member.name || buildData.memberId,
  updatedSearches: JSON.stringify(savedSearches),
  searchName: buildData.searchName,
  totalSearches: savedSearches.length
} }];

const sm = $('State Machine').first().json;
const ad = JSON.parse(sm.actionData || '{}');
const { fetchType, category, query, memberTier, phone } = ad;
const isPremium = memberTier === 'PREMIUM';
const tiers = isPremium ? ['FREE','PREMIUM','ALL'] : ['FREE','ALL'];

const fields = JSON.stringify(['faq_id','category','question','answer','keywords','access_tier','view_count','helpful_count']);
let filters;

if (fetchType === 'faq_list' && category) {
  filters = JSON.stringify([['is_active','=','1'],['access_tier','in',tiers],['category','=',category]]);
} else {
  filters = JSON.stringify([['is_active','=','1'],['access_tier','in',tiers]]);
}

const base = 'http://frontend:8080/api/resource/RIFAH%20FAQ';
const url = base
  + '?filters=' + encodeURIComponent(filters)
  + '&fields='  + encodeURIComponent(fields)
  + '&order_by=view_count%20desc'
  + '&limit=50';

return [{ json: { url, fetchType, category, query, memberTier, phone,
  sessionName: sm.sessionName, sessionData: sm.sessionData, nextStep: sm.nextStep } }];

const raw = $input.first().json;
const items = raw?.data || [];
const build = $('Build F5 FAQ Request').first().json;
const sm = $('State Machine').first().json;
const { fetchType, category, query, sessionName, sessionData, nextStep, phone } = build;

let message = '';
let sessionItems = [];
let step = nextStep || 'FAQ_CATEGORY';

if (fetchType === 'faq_categories') {
  const catMap = {};
  items.forEach(i => { catMap[i.category] = (catMap[i.category] || 0) + 1; });
  const cats = Object.entries(catMap).sort((a,b) => b[1]-a[1]);
  sessionItems = cats.map(([cat, count]) => ({ category: cat, count }));
  const lines = cats.map(([cat, count], idx) => `${idx+1}. *${cat}* (${count} FAQs)`).join('\n');
  const allN = cats.length + 1;
  message = items.length
    ? `❓ *FREQUENTLY ASKED QUESTIONS*\n\nBrowse by category:\n\n${lines}\n${allN}. View All (${items.length} total)\n0. Back\n\n_Reply with a number or type SEARCH [keywords]_`
    : `❓ No FAQs available yet.\n\nReply *0* to go back.`;
  step = 'FAQ_CATEGORY';

} else if (fetchType === 'faq_list') {
  sessionItems = items.map(f => ({ faq_id: f.faq_id, question: f.question, answer: f.answer, view_count: f.view_count || 0, helpful_count: f.helpful_count || 0 }));
  const catLabel = category ? category.toUpperCase() : 'ALL';
  const lines = items.slice(0, 10).map((f, i) => `${i+1}. ${f.question}`).join('\n');
  message = items.length
    ? `📋 *${catLabel} FAQs* (${items.length})\n\n${lines}\n\n_Reply with FAQ number for answer\nOr 0 to go back_`
    : `📋 No FAQs found in this category.\n\nReply *0* to go back.`;
  step = 'FAQ_SELECT';

} else if (fetchType === 'faq_search') {
  const keywords = (query || '').toLowerCase().split(' ').filter(Boolean);
  const scored = items.map(f => {
    let score = 0;
    const text = (f.question + ' ' + f.answer + ' ' + (f.keywords || '')).toLowerCase();
    keywords.forEach(kw => { if (text.includes(kw)) { score += 1; if (f.question.toLowerCase().includes(kw)) score += 2; } });
    return { faq: f, score };
  }).filter(s => s.score > 0).sort((a,b) => b.score - a.score).slice(0, 8);
  sessionItems = scored.map(s => ({ faq_id: s.faq.faq_id, question: s.faq.question, answer: s.faq.answer, view_count: s.faq.view_count || 0 }));
  const lines = scored.map((s, i) => `${i+1}. ${s.faq.question}\n   Category: ${s.faq.category}`).join('\n\n');
  message = scored.length
    ? `🔍 *Search Results: "${query}"*\n\nFound ${scored.length} matching FAQ(s):\n\n${lines}\n\n_Reply with FAQ number for full answer_\n_Or 0 to go back_`
    : `🔍 No FAQs found for "${query}".\n\nTry different keywords or reply *0* to go back.`;
  step = 'FAQ_SELECT';
}

const sd = JSON.parse(sessionData || '{}');
sd.f5_items = sessionItems;
if (category) sd.f5_last_category = category;

return [{ json: {
  message, step, phone,
  sessionName,
  sessionData: JSON.stringify(sd),
  urlSuffix: sessionName ? '/' + encodeURIComponent(sessionName) : '',
}}];

const sm = $('State Machine').first().json;
const ad = JSON.parse(sm.actionData || '{}');
const { faqId, statType } = ad;
const field = statType === 'helpful' ? 'helpful_count' : 'view_count';
// Get current value first — we'll just increment via PUT
return [{ json: { faqId, field, statType, sessionName: sm.sessionName, sessionData: sm.sessionData, nextStep: sm.nextStep, phone: sm.phone, urlSuffix: sm.sessionName ? '/' + encodeURIComponent(sm.sessionName) : '' } }];

// We can't easily do +1 without a GET first; skip stats update for now and just pass through
// (view_count tracking can be added as an enhancement)
const sm = $('State Machine').first().json;
return [{ json: { sessionName: sm.sessionName, sessionData: sm.sessionData, nextStep: sm.nextStep, phone: sm.phone, urlSuffix: sm.sessionName ? '/' + encodeURIComponent(sm.sessionName) : '' } }];

const sm = $('State Machine').first().json;
const ad = JSON.parse(sm.actionData || '{}');
const { ticketType, description, priorityOverride, memberId, memberName, memberPhone, memberTier } = ad;

// Determine priority
const urgentKws = ['urgent','emergency','critical','not working','broken','error','crash','down'];
const lowKws = ['question','how to','feature request','suggestion'];
const desc = (description || '').toLowerCase();
let priority = urgentKws.some(k => desc.includes(k)) ? 'HIGH' : (lowKws.some(k => desc.includes(k)) ? 'LOW' : 'MEDIUM');
if (priorityOverride) priority = priorityOverride;
else if (memberTier === 'PREMIUM' && priority !== 'URGENT') {
  const levels = ['LOW','MEDIUM','HIGH','URGENT'];
  priority = levels[Math.min(levels.indexOf(priority) + 1, 3)];
}
if (ticketType === 'TECHNICAL' && priority === 'MEDIUM') priority = 'HIGH';

const year = new Date().getFullYear();
const ts = Date.now();
const ticketId = `TICKET-${year}-${String(ts).slice(-6)}`;

const payload = {
  ticket_id: ticketId,
  member_id: memberId,
  member_name: memberName,
  member_phone: memberPhone,
  member_tier: memberTier,
  ticket_type: ticketType || 'GENERAL',
  priority,
  subject: (description || '').substring(0, 100),
  description: description || '',
  status: 'OPEN',
  created_at: new Date().toISOString().replace('T',' ').substring(0,19),
  conversation_log: JSON.stringify([{ timestamp: new Date().toISOString(), from: 'user', message: description }]),
  attachments: '[]',
};

const slaMsg = memberTier === 'PREMIUM' ? '4-8 hours' : '24-48 hours';
const confirmMsg = `✅ *Support ticket created!*\n\n🎫 Ticket ID: *${ticketId}*\n📋 Type: ${ticketType}\n⚡ Priority: ${priority}\n\n⏱ Expected Response: ${slaMsg}\n\nWe'll notify you here when our team responds.\n\nReply *TICKETS* to view your tickets\nOr *0* to go back to support menu`;

const sessionData = JSON.parse(sm.sessionData || '{}');
sessionData.f5_last_ticket_id = ticketId;
sessionData.f5_active_ticket_id = ticketId;
delete sessionData.f5_ticket_type;
delete sessionData.f5_ticket_desc;
delete sessionData.f5_priority_override;

return [{ json: { ticketId, payload, confirmMsg, priority, memberTier,
  sessionData: JSON.stringify(sessionData),
  sessionName: sm.sessionName,
  nextStep: sm.nextStep,
  urlSuffix: sm.sessionName ? '/' + encodeURIComponent(sm.sessionName) : '',
  phone: ad.phone || sm.phone,
}}];

const sm = $('State Machine').first().json;
const ad = JSON.parse(sm.actionData || '{}');
const { memberId, memberTier, phone } = ad;

const filters = JSON.stringify([['member_id','=',memberId]]);
const fields = JSON.stringify(['ticket_id','ticket_type','priority','status','subject','description','created_at','resolved_at','conversation_log']);
const ticketsUrl = 'http://frontend:8080/api/resource/RIFAH%20Support%20Ticket'
  + '?filters=' + encodeURIComponent(filters)
  + '&fields=' + encodeURIComponent(fields)
  + '&order_by=creation%20desc&limit=20';

return [{ json: { ticketsUrl, memberId, memberTier, phone,
  sessionName: sm.sessionName, sessionData: sm.sessionData, nextStep: sm.nextStep } }];

const raw = $input.first().json;
const tickets = raw?.data || [];
const pre = $('Get F5 Tickets Pre').first().json;
const { sessionName, sessionData, nextStep, phone } = pre;

function fmtDate(dt) {
  if (!dt) return 'N/A';
  return new Date(dt).toLocaleDateString('en-IN', {day:'numeric',month:'short',year:'numeric'});
}

const open = tickets.filter(t => ['OPEN','IN_PROGRESS','WAITING_USER'].includes(t.status));
const resolved = tickets.filter(t => ['RESOLVED','CLOSED'].includes(t.status));

let msg = `🎫 *MY SUPPORT TICKETS*\n\n`;
msg += `━━━━ OPEN (${open.length}) ━━━━\n`;
if (open.length === 0) msg += 'No open tickets\n';
else open.slice(0,5).forEach(t => { msg += `\n• *${t.ticket_id}*\n  ${(t.subject||'').substring(0,50)}\n  Status: ${t.status} | Priority: ${t.priority}\n  Created: ${fmtDate(t.created_at)}\n`; });

msg += `\n━━━━ RESOLVED (${resolved.length}) ━━━━\n`;
if (resolved.length === 0) msg += 'No resolved tickets\n';
else resolved.slice(0,3).forEach(t => { msg += `\n• *${t.ticket_id}* - ${t.status}\n  Resolved: ${fmtDate(t.resolved_at)}\n`; });

msg += `\n━━━━━━━━━━━━━━━━━━━━━━\n\nReply with ticket ID for details\nOr *0* to go back`;

if (tickets.length === 0) msg = `🎫 *MY SUPPORT TICKETS*\n\nYou have no support tickets yet.\n\nReply *0* to go back or *2* to create a ticket.`;

const sd = JSON.parse(sessionData || '{}');
sd.f5_tickets = tickets.map(t => ({ ticket_id: t.ticket_id, ticket_type: t.ticket_type, priority: t.priority, status: t.status, subject: t.subject, description: t.description, created_at: t.created_at, conversation_log: t.conversation_log || '[]' }));

return [{ json: {
  message: msg, phone,
  sessionData: JSON.stringify(sd),
  sessionName,
  nextStep,
  urlSuffix: sessionName ? '/' + encodeURIComponent(sessionName) : '',
}}];

const sm = $('State Machine').first().json;
const ad = JSON.parse(sm.actionData || '{}');
const { ticketId, message } = ad;
// We'd ideally GET the ticket and append to conversation_log
// For now just acknowledge — full implementation would do a GET+PUT
return [{ json: { ticketId, message, sessionName: sm.sessionName, sessionData: sm.sessionData, nextStep: sm.nextStep, phone: ad.phone || sm.phone, urlSuffix: sm.sessionName ? '/' + encodeURIComponent(sm.sessionName) : '' } }];

// Build PATCH payload to upgrade an existing Free member to Premium
const stateMachineData = $('State Machine').first().json;
const actionData = JSON.parse(stateMachineData.actionData || '{}');

const docname = actionData.existing_member_id;
const existing_rifah_id = actionData.existing_rifah_id || '';

const slug = (actionData.business_name || 'business')
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .replace(/\s+/g, '-')
  .substring(0, 50);

const rifahmart_url = `https://rifahmart.com/${existing_rifah_id}/${slug}`;
const dashboard_username = actionData.confirmed_phone || stateMachineData.phone;
const dashboard_password = 'RIFAH' + Math.floor(Math.random() * 16777216).toString(16).padStart(6, '0').toUpperCase();

const payload = {
  membership_tier: 'PREMIUM',
  status: 'Payment Uploaded',
  rifahmart_url,
  rifahmart_status: 'Featured',
  payment_transaction_id: actionData.payment_transaction_id || '',
  dashboard_username,
  password: dashboard_password
};

return [{
  json: {
    payload,
    docname,
    rifah_id: existing_rifah_id,
    phone: stateMachineData.phone,
    full_name: actionData.full_name || '',
    business_name: actionData.business_name || '',
    dashboard_username,
    password: dashboard_password
  }
}];

